void initializeProductionLogging() {
  // Set up global error handler
  FlutterError.onError = (details) {
    ProductionLogger().logError('Flutter Error', details.exception.toString());
    debugPrint('Flutter Error: ${details.exception}');
  };

  // Set up unhandled exception handler
  Platform.isAndroid ? 
    Zone.current.fork(
      specification: ZoneSpecification(
        handleUncaughtError: (Zone self, ZoneStack zoneStack, Object error, StackTrace stackTrace) {
          ProductionLogger().logError('Unhandled Exception', '$error\n$stackTrace');
          debugPrint('Unhandled Exception: $error\n$stackTrace');
        }
      )
    ) : null;
}